/**
 * Generate Checkout Link Modal Component
 * 
 * Modal dialog for generating payment checkout links. Uses same form structure 
 * as Add Money to Wallet but with /ismartpaycheckout endpoint.
 */

import React, { useEffect, useState } from 'react';
import { createPortal } from 'react-dom';
import { useTranslation } from 'react-i18next';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { countries } from '@/shared/utils/constants/countries-with-flags.js';
import { FlagIcon, LoadingSpinner } from '@/shared/components';
import CustomSelect from '@/shared/components/CustomSelect.jsx';
import { cleanNumberForBackend } from '@/shared/utils/format-utils.js';
import { createCheckoutLinkSchema } from '@/shared/utils/validation/walletSchemas.js';
import { mapInvoiceErrors } from '@/shared/utils/validation/helpers.js';
import { apiRequest } from '@/shared/services/apiClient.js';
import { API_CONFIG } from '@/app/config/apiConfig.js';
import { generateUUID, getUserIdFromStorage } from '@/features/wallet/utils/walletHelpers.js';
import { logger } from '@/shared/utils/logger.js';
import { disbursementService } from '@/features/disbursements/services';
import { useFeeCalculation } from '@/features/disbursements/hooks/useFeeCalculation.js';
import { useDisbursementServices } from '@/features/disbursements/hooks/useDisbursementServices.js';
import { mapProviderToIVerifyOperator, parseAccountName } from '@/features/disbursements/utils/helpers.js';
import CheckoutQrModal from './CheckoutQrModal.jsx';


const GenerateCheckoutLinkModal = ({ isOpen, onClose, onSuccess }) => {
  const { t } = useTranslation();
  const { success, error: showError } = useToast();
  const [qrModalData, setQrModalData] = useState({ isOpen: false, url: '', amount: '', currency: 'GHS' });
  const [successDataCache, setSuccessDataCache] = useState(null);
  const [formData, setFormData] = useState({
    paymentMethod: 'mobileMoney',
    phoneCountryCode: '+233',
    phone: '',
    firstName: '',
    lastName: '',
    email: '',
    provider: '',
    accountNumber: '',
    amount: '',
    cardNumber: '',
    cardExpiry: '',
    cardCvv: '',
    cardholderName: '',
    items: [{ description: '', quantity: '', unitPrice: '', total: 0 }]
  });

  const selectedPhoneCountry = countries.find(c => c.dialCode === formData.phoneCountryCode) || countries.find(c => c.code === 'GH');
  const [formErrors, setFormErrors] = useState({});
  const [itemErrors, setItemErrors] = useState({});
  const [isLoading, setIsLoading] = useState(false);
  const [isValidatingAccount, setIsValidatingAccount] = useState(false);
  const [accountDetailsFetched, setAccountDetailsFetched] = useState(false);
  const [cachedAccountDetails, setCachedAccountDetails] = useState({ firstName: '', lastName: '' });

  const { collectionServiceId } = useDisbursementServices();
  const { feeData, setFeeData, checkFee } = useFeeCalculation(collectionServiceId);

  const handleItemChange = (index, field, value) => {
    setFormData(prev => {
      const newItems = [...prev.items];
      newItems[index] = {
        ...newItems[index],
        [field]: value
      };

      if (field === 'quantity' || field === 'unitPrice') {
        const qty = parseFloat(newItems[index].quantity) || 0;
        const price = parseFloat(newItems[index].unitPrice) || 0;
        newItems[index].total = qty * price;
      }

      // Calculate total amount
      const totalAmount = newItems.reduce((sum, item) => sum + (parseFloat(item.total) || 0), 0);

      return {
        ...prev,
        items: newItems,
        amount: totalAmount > 0 ? totalAmount.toFixed(2) : ''
      };
    });

    // Clear item error if it exists
    const errorKey = `items.${index}.${field}`;
    if (itemErrors[errorKey]) {
      setItemErrors(prev => {
        const next = { ...prev };
        delete next[errorKey];
        return next;
      });
    }
  };

  const addNewItem = () => {
    setFormData(prev => ({
      ...prev,
      items: [...prev.items, { description: '', quantity: '', unitPrice: '', total: 0 }]
    }));
  };

  const removeItem = (index) => {
    setFormData(prev => {
      const newItems = prev.items.filter((_, i) => i !== index);
      const totalAmount = newItems.reduce((sum, item) => sum + (parseFloat(item.total) || 0), 0);
      return {
        ...prev,
        items: newItems,
        amount: totalAmount > 0 ? totalAmount.toFixed(2) : ''
      };
    });

    setItemErrors({});
  };

  const providerToNetwork = {
    'MTN': 'mtn',
    'TELECEL': 'telecel',
    'AIRTEL-TIGO': 'airteltigo'
  };

  const handleChange = (e) => {
    const { name, value } = e.target;

    if (name === 'phone' && value && value.startsWith('0')) {
      setFormData(prev => ({
        ...prev,
        [name]: value.substring(1)
      }));
      return;
    }

    setFormData(prev => ({
      ...prev,
      [name]: value
    }));

    if (formErrors[name]) {
      setFormErrors((prev) => {
        const next = { ...prev };
        delete next[name];
        return next;
      });
    }

    if (['phone', 'phoneCountryCode', 'provider'].includes(name)) {
      setAccountDetailsFetched(false);
    }
    if (name === 'amount' && cachedAccountDetails.firstName) {
      setFormData((prev) => ({
        ...prev,
        firstName: cachedAccountDetails.firstName,
        lastName: cachedAccountDetails.lastName,
      }));
      setAccountDetailsFetched(true);
    }
  };

  useEffect(() => {
    const amountValue = Number(formData.amount);
    if (!formData.amount || Number.isNaN(amountValue) || amountValue <= 0) {
      setFeeData(null);
      return;
    }
    if (!collectionServiceId) {
      setFeeData(null);
      return;
    }

    const channel = formData.paymentMethod === 'bank' ? 'BANK' : 'MOMO';
    checkFee(amountValue, channel);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [formData.amount, formData.paymentMethod, collectionServiceId]);


  const canFetchAccountDetails = () => {
    if (!formData.phone || !formData.phone.trim()) {
      return false;
    }
    if (!formData.provider || !formData.provider.trim()) {
      return false;
    }
    return true;
  };

  const handleFetchAccountDetails = async () => {
    if (!formData.phone || !formData.phone.trim()) {
      setFormErrors((prev) => ({
        ...prev,
        phone: t('invalidPhoneNumber', { ns: 'wallet', defaultValue: 'Enter a valid phone number' }),
      }));
      showError(t('invalidPhoneNumber', { ns: 'wallet', defaultValue: 'Enter a valid phone number' }));
      return;
    }

    if (!formData.provider) {
      setFormErrors((prev) => ({
        ...prev,
        provider: t('providerRequired', { ns: 'wallet', defaultValue: 'Select a provider' }),
      }));
      showError(t('providerRequired', { ns: 'wallet', defaultValue: 'Select a provider' }));
      return;
    }

    setIsValidatingAccount(true);

    try {
      let mobileNumber = formData.phone.trim();
      if (mobileNumber.startsWith('+233')) {
        mobileNumber = mobileNumber.substring(4);
      } else if (mobileNumber.startsWith('233')) {
        mobileNumber = mobileNumber.substring(3);
      }
      if (mobileNumber.startsWith('0')) {
        mobileNumber = mobileNumber.substring(1);
      }
      mobileNumber = '0' + mobileNumber;

      const operator = mapProviderToIVerifyOperator(formData.provider);
      const response = await disbursementService.verifyMobileMoneyIdentity({
        mobileNumber,
        operator,
      });

      if (response?.status === 'success' && response?.name) {
        const { firstName, surname } = parseAccountName(response.name);

        setAccountDetailsFetched(true);
        setFormData((prev) => ({
          ...prev,
          firstName,
          lastName: surname,
        }));
        setCachedAccountDetails({ firstName, lastName: surname });
        setFormErrors((prev) => {
          const next = { ...prev };
          delete next.phone;
          delete next.provider;
          delete next.firstName;
          delete next.lastName;
          delete next.accountNumber;
          return next;
        });

        success(t('accountValidated', { ns: 'wallet', defaultValue: 'Account details fetched successfully.' }));
        return;
      }

      showError(t('pleaseTryAgain', { ns: 'common', defaultValue: 'Please try again.' }));
    } catch (error) {
      logger.error('Failed to verify account identity', { error });
      showError(t('pleaseTryAgain', { ns: 'common', defaultValue: 'Please try again.' }));
    } finally {
      setIsValidatingAccount(false);
    }
  };



  const executeCheckout = async (checkoutContext) => {
    if (!checkoutContext) { return; }
    const { payload, parsedValues } = checkoutContext;

    try {
      setIsLoading(true);
      const recipientId = getUserIdFromStorage();
      const headers = {
        'X-Skip-Auth': '1',
        'Content-Type': 'application/json'
      };

      if (recipientId) {
        headers['recipientId'] = String(recipientId);
      }

      // IMPORTANT: Checkout generation must always use the collections gateway
      // attached to VITE_COLLECTION_API_URL (staging/development).
      const endpoint = '/ismartpaycheckout';
      const baseUrl = API_CONFIG.COLLECTION_BASE_URL;

      logger.debug('Checkout Request', {
        url: `${baseUrl}${endpoint}`,
        headers: headers,
        payload: payload
      });

      const response = await apiRequest(endpoint, {
        method: 'POST',
        headers: headers,
        body: JSON.stringify(payload),
        // Force collections base URL so we never accidentally hit a security service
        baseUrl
      });


      logger.debug('Checkout Response', { response });

      const isSuccess = (
        response?.Status === 'Success' ||
        response?.Status === 'success' ||
        response?.status === 'success' ||
        response?.status === 'Success' ||
        response?.ResponseCode === '0000'
      );
      // url is at top-level in the response: { Status, ResponseCode, Data, sessionid, url, expirytime }
      const checkoutUrl = response?.url || response?.Data?.url || response?.data?.url;
      const hasData = response?.Data || response?.data || checkoutUrl;

      if (response && isSuccess && hasData) {
        success('✓ Checkout Generated Successfully');

        const successData = { amount: parsedValues.amount };
        setSuccessDataCache(successData);

        if (checkoutUrl) {
          setQrModalData({
            isOpen: true,
            url: checkoutUrl,
            amount: parsedValues.amount,
            currency: 'GHS'
          });
        } else {
          setFormData({
            paymentMethod: 'mobileMoney',
            phoneCountryCode: '+233',
            phone: '',
            firstName: '',
            lastName: '',
            email: '',
            provider: '',
            accountNumber: '',
            amount: '',
            cardNumber: '',
            cardExpiry: '',
            cardCvv: '',
            cardholderName: '',
            items: [{ description: '', quantity: '', unitPrice: '', total: 0 }]
          });
          setFormErrors({});
          setItemErrors({});
          setAccountDetailsFetched(false);
          setCachedAccountDetails({ firstName: '', lastName: '' });

          if (typeof onSuccess === 'function') { onSuccess(successData); }
          if (typeof onClose === 'function') { onClose(); }
        }
      } else {
        showError(t('checkoutFailed', { ns: 'collections', defaultValue: 'Checkout generation failed' }));
        return;
      }
    } catch (err) {
      logger.error('Error generating checkout', {
        error: err,
        details: {
          message: err?.message,
          details: err?.details,
          response: err?.response,
          responseData: err?.response?.data,
          fullError: err
        }
      });
      showError(t('checkoutFailed', { ns: 'collections', defaultValue: 'Checkout generation failed' }));
    } finally {
      setIsLoading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const validationData = {
      ...formData,
      provider: formData.provider ? formData.provider.toLowerCase() : undefined
    };

    const schema = createCheckoutLinkSchema(t);
    const result = schema.safeParse(validationData);

    if (!result.success) {
      const { formErrors: fErrors, itemErrors: iErrors } = mapInvoiceErrors(result.error);
      setFormErrors(fErrors);
      setItemErrors(iErrors);
      const firstFormError = Object.values(fErrors)[0];
      const firstItemError = Object.values(iErrors)[0];
      const errorToShow = firstFormError || firstItemError;
      if (errorToShow) {
        showError(errorToShow);
      }
      return;
    }

    const parsedValues = result.data;
    setFormErrors({});
    setItemErrors({});

    try {
      const firstName = parsedValues.firstName || '';
      const lastName = parsedValues.lastName || '';
      const email = parsedValues.email || '';
      const referenced = generateUUID();

      let payload;
      const baseAmount = parseFloat(parsedValues.amount) || 0;
      const items = (formData.items || []).map(item => ({
        description: item.description || '',
        quantity: parseFloat(item.quantity) || 0,
        unitPrice: parseFloat(item.unitPrice) || 0,
        total: parseFloat(item.total) || 0
      }));

      if (parsedValues.paymentMethod === 'card') {
        payload = {
          referenceid: referenced,
          paymentType: 'checkout',
          amount: baseAmount.toFixed(2),
          currency: 'GHS',
          narration: 'Generate Checkout',
          items: items,
          customer: {
            firstName: firstName || '',
            lastName: lastName || '',
            phoneNumber: '',
            email: email || 'Test@ismartghana.com',
            network: 'CARD'
          }
        };
      } else {
        const cleanedCustPhoneLocal = parsedValues.phone
          ? cleanNumberForBackend(parsedValues.phone.trim())
          : '';
        const cleanedCustCountry = parsedValues.phoneCountryCode
          ? cleanNumberForBackend(parsedValues.phoneCountryCode)
          : '';
        const customerFullPhone = cleanedCustPhoneLocal
          ? `${cleanedCustCountry}${cleanedCustPhoneLocal}`
          : '';

        const provider = parsedValues.provider === 'mtn' ? 'MTN' : parsedValues.provider === 'telecel' ? 'TELECEL' : parsedValues.provider === 'airtel-tigo' ? 'AIRTEL-TIGO' : parsedValues.provider.toUpperCase();
        const apiNetwork = providerToNetwork[provider] || provider.toLowerCase().replace('-', '');

        payload = {
          referenceid: referenced,
          paymentType: 'checkout',
          amount: baseAmount.toFixed(2),
          currency: 'GHS',
          narration: 'Generate Checkout',
          items: items,
          customer: {
            firstName: firstName || '',
            lastName: lastName || '',
            phoneNumber: customerFullPhone,
            email: email || 'Test@ismartghana.com',
            network: parsedValues.paymentMethod === 'bank'
              ? provider.toLowerCase().replace('-', '')
              : apiNetwork
          }
        };
      }

      await executeCheckout({ payload, parsedValues });
    } catch (err) {
      logger.error('Error generating checkout', { error: err });
      showError(t('checkoutFailed', { ns: 'collections', defaultValue: 'Checkout generation failed' }));
    } finally {
      setIsLoading(false);
    }
  };

  const handleProviderSelect = (provider) => {
    const providerUpper = provider === 'mtn' ? 'MTN' : provider === 'telecel' ? 'TELECEL' : provider === 'airtel-tigo' ? 'AIRTEL-TIGO' : provider;
    setFormData((prev) => ({
      ...prev,
      provider: providerUpper,
    }));
    setAccountDetailsFetched(false);

    setFormErrors((prev) => {
      if (!prev.provider) {
        return prev;
      }
      const next = { ...prev };
      delete next.provider;
      return next;
    });
  };



  const handleClose = () => {
    setFormData({
      paymentMethod: 'mobileMoney',
      phoneCountryCode: '+233',
      phone: '',
      firstName: '',
      lastName: '',
      provider: '',
      accountNumber: '',
      amount: '',
      cardNumber: '',
      cardExpiry: '',
      cardCvv: '',
      cardholderName: '',
      items: [{ description: '', quantity: '', unitPrice: '', total: 0 }]
    });
    setFormErrors({});
    setItemErrors({});
    setAccountDetailsFetched(false);
    setCachedAccountDetails({ firstName: '', lastName: '' });
    if (typeof onClose === 'function') { onClose(); }
  };

  const handleQrModalClose = () => {
    setQrModalData({ isOpen: false, url: '', amount: '', currency: 'GHS' });
    setFormData({
      paymentMethod: 'mobileMoney',
      phoneCountryCode: '+233',
      phone: '',
      firstName: '',
      lastName: '',
      email: '',
      provider: '',
      accountNumber: '',
      amount: '',
      cardNumber: '',
      cardExpiry: '',
      cardCvv: '',
      cardholderName: '',
      items: [{ description: '', quantity: '', unitPrice: '', total: 0 }]
    });
    setFormErrors({});
    setItemErrors({});
    setAccountDetailsFetched(false);
    setCachedAccountDetails({ firstName: '', lastName: '' });

    if (successDataCache) {
      if (typeof onSuccess === 'function') { onSuccess(successDataCache); }
      setSuccessDataCache(null);
    }
    if (typeof onClose === 'function') { onClose(); }
  };

  if (!isOpen) { return null; }

  return createPortal(
    <>
      <div style={{
      position: 'fixed',
      inset: 0,
      backgroundColor: 'rgba(0,0,0,0.5)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      zIndex: 9999,
      backdropFilter: 'blur(4px)',
      padding: '16px',
      overflowY: 'auto'
    }}>
      <div style={{
        backgroundColor: 'var(--card)',
        borderRadius: 16,
        padding: 32,
        width: '100%',
        maxWidth: 480,
        boxShadow: 'var(--shadow-xl)',
        animation: 'slideIn 0.3s ease-out',
        transition: 'background-color var(--transition-theme)',
        margin: 'auto',
        position: 'relative'
      }}>
        {/* Close Button */}
        <button
          onClick={handleClose}
          style={{
            position: 'absolute',
            top: 16,
            right: 16,
            background: 'transparent',
            border: 'none',
            fontSize: '24px',
            cursor: 'pointer',
            color: 'var(--text-muted)',
            padding: '4px',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            transition: 'color var(--transition-base)'
          }}
          onMouseEnter={(e) => e.target.style.color = 'var(--text-primary)'}
          onMouseLeave={(e) => e.target.style.color = 'var(--text-muted)'}
        >
          <span className="material-symbols-outlined">close</span>
        </button>

        {/* Header */}
        <div style={{
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          marginBottom: 24
        }}>
          <div style={{
            width: 64,
            height: 64,
            borderRadius: '50%',
            background: 'var(--accent)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            marginBottom: 16,
            boxShadow: '0 4px 12px rgba(0, 72, 149, 0.3)'
          }}>
            <span className="material-symbols-outlined" style={{
              fontSize: 32,
              color: 'white'
            }}>
              shopping_cart
            </span>
          </div>
          <h3 style={{
            margin: 0,
            marginBottom: 8,
            color: 'var(--text-primary)',
            fontSize: '24px',
            fontWeight: 700
          }}>
            {t('generateCheckout', { ns: 'dashboard', defaultValue: 'Generate Checkout' })}
          </h3>
        </div>

        {/* Form */}
        <form onSubmit={handleSubmit}>
          {/* Email */}
          <div style={{ marginBottom: 20 }}>
            <label style={{
              display: 'block',
              marginBottom: 8,
              fontWeight: 600,
              color: 'var(--text-primary)',
              fontSize: '14px'
            }}>
              {t('email', { ns: 'common', defaultValue: 'Email' })}
            </label>
            <input
              type="email"
              name="email"
              value={formData.email}
              onChange={handleChange}
              placeholder="email@example.com"
              style={{
                width: '100%',
                padding: '14px 16px',
                fontSize: '15px',
                borderRadius: 10,
                border: '2px solid var(--border-secondary)',
                background: 'var(--bg-input)',
                color: 'var(--text-primary)',
                transition: 'all var(--transition-base)',
                boxSizing: 'border-box'
              }}
            />
            {formErrors.email && (
              <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '6px' }}>
                {formErrors.email}
              </p>
            )}
          </div>

          {/* Provider */}
          <div style={{ marginBottom: 20 }}>
            <div style={{
              display: 'grid',
              gridTemplateColumns: '1fr 1fr 1fr',
              gap: 12
            }}>
              <button
                type="button"
                onClick={() => handleProviderSelect('mtn')}
                style={{
                  padding: '16px',
                  borderRadius: 10,
                  border: `2px solid ${formData.provider === 'MTN' ? '#FFC107' : 'var(--border-secondary)'}`,
                  background: formData.provider === 'MTN' ? 'rgba(255, 193, 7, 0.1)' : 'var(--bg-input)',
                  cursor: 'pointer',
                  transition: 'all var(--transition-base)',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  gap: 8,
                  fontWeight: 600,
                  color: formData.provider === 'MTN' ? '#FFC107' : 'var(--text-primary)'
                }}
              >
                <img
                  src="/assets/mtnlogo.png"
                  alt="MTN"
                  style={{ width: 24, height: 24, objectFit: 'contain' }}
                />
                MTN
              </button>
              <button
                type="button"
                onClick={() => handleProviderSelect('telecel')}
                style={{
                  padding: '16px',
                  borderRadius: 10,
                  border: `2px solid ${formData.provider === 'TELECEL' ? '#DC2626' : 'var(--border-secondary)'}`,
                  background: formData.provider === 'TELECEL' ? 'rgba(220, 38, 38, 0.1)' : 'var(--bg-input)',
                  cursor: 'pointer',
                  transition: 'all var(--transition-base)',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  gap: 8,
                  fontWeight: 600,
                  color: formData.provider === 'TELECEL' ? '#DC2626' : 'var(--text-primary)'
                }}
              >
                <img
                  src="/assets/telecellogo.png"
                  alt="TELECEL"
                  style={{ width: 24, height: 24, objectFit: 'contain' }}
                />
                TELECEL
              </button>
              <button
                type="button"
                onClick={() => handleProviderSelect('airtel-tigo')}
                style={{
                  padding: '16px',
                  borderRadius: 10,
                  border: `2px solid ${formData.provider === 'AIRTEL-TIGO' ? '#E53E3E' : 'var(--border-secondary)'}`,
                  background: formData.provider === 'AIRTEL-TIGO' ? 'rgba(229, 62, 62, 0.1)' : 'var(--bg-input)',
                  cursor: 'pointer',
                  transition: 'all var(--transition-base)',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  gap: 8,
                  fontWeight: 600,
                  color: formData.provider === 'AIRTEL-TIGO' ? '#E53E3E' : 'var(--text-primary)'
                }}
              >
                <img
                  src="/assets/airtel-tigo.png"
                  alt="Airtel Tigo"
                  style={{ width: 24, height: 24, objectFit: 'contain' }}
                />
                Airtel Tigo
              </button>
            </div>
            {formErrors.provider && (
              <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '6px' }}>
                {formErrors.provider}
              </p>
            )}
          </div>

          {/* Phone */}
          <div style={{ marginBottom: 20 }}>
            <label style={{
              display: 'block',
              marginBottom: 8,
              fontWeight: 600,
              color: 'var(--text-primary)',
              fontSize: '14px'
            }}>
              {t('phoneNumber', { ns: 'wallet' })}
            </label>
            <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
              <div style={{ position: 'relative', width: '120px', flexShrink: 0 }}>
                <span style={{
                  position: 'absolute',
                  left: '12px',
                  top: '50%',
                  transform: 'translateY(-50%)',
                  pointerEvents: 'none',
                  zIndex: 1,
                  display: 'flex',
                  alignItems: 'center'
                }}>
                  <FlagIcon
                    countryCode={selectedPhoneCountry?.code}
                    size="1.1em"
                  />
                </span>
                <CustomSelect
                  name="phoneCountryCode"
                  value={formData.phoneCountryCode}
                  onChange={handleChange}
                  options={countries.map((country) => ({
                    value: country.dialCode,
                    label: country.dialCode,
                    name: country.name,
                    countryCode: country.code,
                  }))}
                  searchable
                  showCheckmark={false}
                  style={{ width: '100%' }}
                />
              </div>
              <input
                type="tel"
                name="phone"
                value={formData.phone}
                onChange={handleChange}
                placeholder="555123456"
                maxLength={10}
                style={{
                  flex: 1,
                  padding: '14px 16px',
                  fontSize: '15px',
                  borderRadius: 10,
                  border: '2px solid var(--border-secondary)',
                  background: 'var(--bg-input)',
                  color: 'var(--text-primary)',
                  transition: 'all var(--transition-base)',
                  boxSizing: 'border-box'
                }}
              />
            </div>
            {formErrors.phone && (
              <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '6px' }}>
                {formErrors.phone}
              </p>
            )}
          </div>

          {/* Fetch Account Details */}
          <div style={{ marginBottom: 20 }}>
            <button
              type="button"
              onClick={handleFetchAccountDetails}
              disabled={isValidatingAccount || accountDetailsFetched || !canFetchAccountDetails()}
              style={{
                padding: '10px 16px',
                borderRadius: 10,
                border: '1px solid var(--border-secondary)',
                backgroundColor: isValidatingAccount || accountDetailsFetched || !canFetchAccountDetails()
                  ? 'var(--bg-tertiary)'
                  : 'var(--accent)',
                color: isValidatingAccount || accountDetailsFetched || !canFetchAccountDetails()
                  ? 'var(--text-muted)'
                  : 'var(--text-inverse)',
                fontSize: '13px',
                fontWeight: 600,
                cursor: isValidatingAccount || accountDetailsFetched || !canFetchAccountDetails()
                  ? 'not-allowed'
                  : 'pointer',
                transition: 'all var(--transition-base)',
                display: 'inline-flex',
                alignItems: 'center',
                gap: '6px',
              }}
            >
              <span className="material-symbols-outlined" style={{ fontSize: '16px' }}>
                {isValidatingAccount ? 'hourglass_top' : accountDetailsFetched ? 'check_circle' : 'badge'}
              </span>
              {isValidatingAccount
                ? t('fetching', { ns: 'wallet', defaultValue: 'Fetching...' })
                : accountDetailsFetched
                  ? t('detailsFetched', { ns: 'wallet', defaultValue: 'Details Fetched' })
                  : t('fetchAccountDetails', { ns: 'wallet', defaultValue: 'Fetch Account Details' })}
            </button>
          </div>

          {/* Account Details */}
          {(accountDetailsFetched || formData.firstName || formData.lastName) && (
            <div style={{
              display: 'grid',
              gridTemplateColumns: '1fr 1fr',
              gap: 12,
              marginBottom: 20
            }}>
              <div>
                <label style={{
                  display: 'block',
                  marginBottom: 8,
                  fontWeight: 600,
                  color: 'var(--text-primary)',
                  fontSize: '14px'
                }}>
                  {t('firstName', { ns: 'common', defaultValue: 'First Name' })}
                </label>
                <input
                  type="text"
                  name="firstName"
                  value={formData.firstName}
                  readOnly={true}
                  disabled={true}
                  style={{
                    width: '100%',
                    padding: '14px 16px',
                    fontSize: '15px',
                    borderRadius: 10,
                    border: '2px solid var(--border-secondary)',
                    background: 'var(--bg-tertiary)',
                    color: 'var(--text-primary)',
                    boxSizing: 'border-box',
                    cursor: 'not-allowed'
                  }}
                />
              </div>
              <div>
                <label style={{
                  display: 'block',
                  marginBottom: 8,
                  fontWeight: 600,
                  color: 'var(--text-primary)',
                  fontSize: '14px'
                }}>
                  {t('lastName', { ns: 'common', defaultValue: 'Surname' })}
                </label>
                <input
                  type="text"
                  name="lastName"
                  value={formData.lastName}
                  readOnly={true}
                  disabled={true}
                  style={{
                    width: '100%',
                    padding: '14px 16px',
                    fontSize: '15px',
                    borderRadius: 10,
                    border: '2px solid var(--border-secondary)',
                    background: 'var(--bg-tertiary)',
                    color: 'var(--text-primary)',
                    boxSizing: 'border-box',
                    cursor: 'not-allowed'
                  }}
                />
              </div>
            </div>
          )}

          {/* Items Section */}
          <div style={{ marginBottom: 20 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 12 }}>
              <label style={{
                fontWeight: 600,
                color: 'var(--text-primary)',
                fontSize: '14px'
              }}>
                {t('items', { ns: 'invoicing', defaultValue: 'Items' })}
              </label>
              <button
                type="button"
                onClick={addNewItem}
                style={{
                  display: 'inline-flex',
                  alignItems: 'center',
                  gap: '4px',
                  padding: '6px 12px',
                  borderRadius: 8,
                  border: '1px solid var(--border-secondary)',
                  background: 'var(--bg-input)',
                  color: 'var(--accent)',
                  fontSize: '13px',
                  fontWeight: 600,
                  cursor: 'pointer',
                  transition: 'all var(--transition-base)'
                }}
              >
                <span className="material-symbols-outlined" style={{ fontSize: '16px' }}>add</span>
                {t('addItem', { ns: 'invoicing', defaultValue: 'Add Item' })}
              </button>
            </div>

            <div style={{
              maxHeight: '260px',
              overflowY: 'auto',
              paddingRight: '4px',
              marginBottom: 16,
              border: formData.items.length > 0 ? '1px solid var(--border-primary)' : 'none',
              borderRadius: 12,
              padding: formData.items.length > 0 ? '8px' : '0'
            }}>
              {formData.items.map((item, index) => (
                <div
                  key={index}
                  style={{
                    backgroundColor: 'var(--bg-secondary)',
                    border: '1px solid var(--border-primary)',
                    borderRadius: 10,
                    padding: 12,
                    marginBottom: index === formData.items.length - 1 ? 0 : 12,
                  }}
                >
                  {/* Item Header */}
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 10 }}>
                    <span style={{ fontSize: '13px', fontWeight: 700, color: 'var(--text-muted)' }}>
                      {t('item', { ns: 'invoicing', defaultValue: 'Item' })} #{index + 1}
                    </span>
                    {formData.items.length > 1 && (
                      <button
                        type="button"
                        onClick={() => removeItem(index)}
                        style={{
                          background: 'transparent',
                          border: 'none',
                          color: 'var(--error)',
                          cursor: 'pointer',
                          padding: '4px',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          fontSize: '13px',
                          fontWeight: 500,
                          gap: '4px'
                        }}
                      >
                        <span className="material-symbols-outlined" style={{ fontSize: '16px' }}>delete</span>
                        {t('remove', { ns: 'invoicing', defaultValue: 'Remove' })}
                      </button>
                    )}
                  </div>

                  {/* Description */}
                  <div style={{ marginBottom: 10 }}>
                    <input
                      type="text"
                      value={item.description}
                      onChange={(e) => handleItemChange(index, 'description', e.target.value)}
                      placeholder={t('itemDescription', { ns: 'invoicing', defaultValue: 'Item description' })}
                      style={{
                        width: '100%',
                        padding: '10px 12px',
                        fontSize: '14px',
                        borderRadius: 8,
                        border: `2px solid ${itemErrors[`items.${index}.description`] ? 'var(--error)' : 'var(--border-secondary)'}`,
                        background: 'var(--bg-input)',
                        color: 'var(--text-primary)',
                        boxSizing: 'border-box'
                      }}
                    />
                    {itemErrors[`items.${index}.description`] && (
                      <p style={{ color: 'var(--error)', fontSize: '11px', marginTop: '4px', marginBottom: 0 }}>
                        {itemErrors[`items.${index}.description`]}
                      </p>
                    )}
                  </div>

                  {/* Qty & Price */}
                  <div style={{ display: 'grid', gridTemplateColumns: '1fr 1.2fr', gap: 10 }}>
                    <div>
                      <input
                        type="number"
                        value={item.quantity || ''}
                        onChange={(e) => handleItemChange(index, 'quantity', e.target.value)}
                        placeholder={t('quantity', { ns: 'invoicing', defaultValue: 'Qty' })}
                        min="1"
                        style={{
                          width: '100%',
                          padding: '10px 12px',
                          fontSize: '14px',
                          borderRadius: 8,
                          border: `2px solid ${itemErrors[`items.${index}.quantity`] ? 'var(--error)' : 'var(--border-secondary)'}`,
                          background: 'var(--bg-input)',
                          color: 'var(--text-primary)',
                          boxSizing: 'border-box'
                        }}
                      />
                      {itemErrors[`items.${index}.quantity`] && (
                        <p style={{ color: 'var(--error)', fontSize: '11px', marginTop: '4px', marginBottom: 0 }}>
                          {itemErrors[`items.${index}.quantity`]}
                        </p>
                      )}
                    </div>
                    <div>
                      <div style={{ position: 'relative' }}>
                        <span style={{
                          position: 'absolute',
                          left: 10,
                          top: '50%',
                          transform: 'translateY(-50%)',
                          fontSize: '12px',
                          fontWeight: 600,
                          color: 'var(--text-muted)',
                          pointerEvents: 'none'
                        }}>
                          GHS
                        </span>
                        <input
                          type="number"
                          value={item.unitPrice || ''}
                          onChange={(e) => handleItemChange(index, 'unitPrice', e.target.value)}
                          placeholder="0.00"
                          step="0.01"
                          style={{
                            width: '100%',
                            padding: '10px 12px 10px 42px',
                            fontSize: '14px',
                            borderRadius: 8,
                            border: `2px solid ${itemErrors[`items.${index}.unitPrice`] ? 'var(--error)' : 'var(--border-secondary)'}`,
                            background: 'var(--bg-input)',
                            color: 'var(--text-primary)',
                            boxSizing: 'border-box'
                          }}
                        />
                      </div>
                      {itemErrors[`items.${index}.unitPrice`] && (
                        <p style={{ color: 'var(--error)', fontSize: '11px', marginTop: '4px', marginBottom: 0 }}>
                          {itemErrors[`items.${index}.unitPrice`]}
                        </p>
                      )}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Amount */}
          <div style={{ marginBottom: 20 }}>
            <label style={{
              display: 'block',
              marginBottom: 8,
              fontWeight: 600,
              color: 'var(--text-primary)',
              fontSize: '14px'
            }}>
              {t('amount', { ns: 'wallet', defaultValue: 'Amount' })}
              <span style={{ color: 'var(--error)', marginLeft: '4px' }}>*</span>
            </label>
            <div style={{ position: 'relative' }}>
              <span style={{
                position: 'absolute',
                left: 16,
                top: '50%',
                transform: 'translateY(-50%)',
                fontSize: '15px',
                fontWeight: 600,
                color: 'var(--text-muted)',
                pointerEvents: 'none'
              }}>
                GHS
              </span>
              <input
                type="number"
                name="amount"
                value={formData.amount}
                readOnly={true}
                disabled={true}
                placeholder="0.00"
                style={{
                  width: '100%',
                  padding: '14px 16px 14px 50px',
                  fontSize: '15px',
                  borderRadius: 10,
                  border: '2px solid var(--border-secondary)',
                  background: 'var(--bg-tertiary)',
                  color: 'var(--text-primary)',
                  transition: 'all var(--transition-base)',
                  boxSizing: 'border-box',
                  cursor: 'not-allowed'
                }}
              />
            </div>
            {formErrors.amount && (
              <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '6px' }}>
                {formErrors.amount}
              </p>
            )}
            {feeData && (
              <p style={{ color: 'var(--text-muted)', fontSize: '12px', marginTop: '6px' }}>
                {t('fee', { ns: 'wallet', defaultValue: 'Fee' })}: GHS {feeData.totalFee || 0}
              </p>
            )}
          </div>

          {/* Submit Button */}
          <button
            type="submit"
            disabled={isLoading}
            style={{
              width: '100%',
              padding: '14px 16px',
              borderRadius: 10,
              border: 'none',
              backgroundColor: isLoading ? 'var(--bg-tertiary)' : 'var(--accent)',
              color: isLoading ? 'var(--text-muted)' : 'var(--text-inverse)',
              fontSize: '15px',
              fontWeight: 700,
              cursor: isLoading ? 'not-allowed' : 'pointer',
              transition: 'all var(--transition-base)',
              display: 'inline-flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: '8px'
            }}
          >
            {isLoading ? (
              <>
                <LoadingSpinner size="small" color="white" />
                {t('generating', { ns: 'collections', defaultValue: 'Generating...' })}
              </>
            ) : (
              <>
                <span className="material-symbols-outlined">shopping_cart</span>
                {t('generateCheckout', { ns: 'dashboard', defaultValue: 'Generate Checkout' })}
              </>
            )}
          </button>
        </form>


      </div>
    </div>
    <CheckoutQrModal
      isOpen={qrModalData.isOpen}
      url={qrModalData.url}
      amount={qrModalData.amount}
      currency={qrModalData.currency}
      onClose={handleQrModalClose}
    />
    </>,
    document.body
  );
};

export default GenerateCheckoutLinkModal;
