import React from 'react';
import { createPortal } from 'react-dom';
import { QRCodeSVG } from 'qrcode.react';

const CheckoutQrModal = ({ isOpen, url, amount, currency = 'GHS', onClose }) => {
  if (!isOpen || !url) { return null; }

  const modal = (
    <div
      style={{
        position: 'fixed',
        inset: 0,
        zIndex: 10500,
        background: 'rgba(0,0,0,0.65)',
        backdropFilter: 'blur(8px)',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        padding: '20px',
        animation: 'fadeIn 0.2s ease-out'
      }}
      onClick={onClose}
    >
      <div
        style={{
          background: 'var(--card, #ffffff)',
          borderRadius: '24px',
          width: '100%',
          maxWidth: '440px',
          boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.4)',
          border: '1px solid var(--border-primary, rgba(0, 0, 0, 0.1))',
          padding: '32px 24px',
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          textAlign: 'center',
          position: 'relative',
          animation: 'scaleIn 0.3s cubic-bezier(0.34, 1.56, 0.64, 1)'
        }}
        onClick={(e) => e.stopPropagation()}
      >
        {/* Header Icon */}
        <div
          style={{
            width: '56px',
            height: '56px',
            borderRadius: '50%',
            background: 'rgba(0, 122, 255, 0.1)',
            color: 'var(--accent, #007aff)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            marginBottom: '16px'
          }}
        >
          <span className="material-symbols-outlined" style={{ fontSize: '32px' }}>
            qr_code_2
          </span>
        </div>

        {/* Title & Desc */}
        <h3
          style={{
            margin: '0 0 8px 0',
            fontSize: '20px',
            fontWeight: 700,
            color: 'var(--text-primary, #111827)'
          }}
        >
          Scan to Pay
        </h3>
        <p
          style={{
            margin: '0 0 24px 0',
            fontSize: '14px',
            color: 'var(--text-secondary, #4b5563)',
            lineHeight: '1.5',
            padding: '0 10px'
          }}
        >
          Please scan the QR code below to complete your payment of{' '}
          <strong style={{ color: 'var(--accent, #007aff)' }}>
            {currency} {parseFloat(amount || 0).toFixed(2)}
          </strong>
        </p>

        {/* QR Code Container */}
        <div
          style={{
            background: '#ffffff',
            padding: '16px',
            borderRadius: '16px',
            boxShadow: '0 4px 20px rgba(0, 0, 0, 0.08)',
            border: '1px solid rgba(0, 0, 0, 0.05)',
            marginBottom: '24px',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center'
          }}
        >
          <QRCodeSVG
            value={url}
            size={200}
            level="H"
            includeMargin={true}
          />
        </div>

        {/* Info Banner */}
        <div
          style={{
            background: 'var(--bg-secondary, #f3f4f6)',
            borderRadius: '12px',
            padding: '12px 16px',
            fontSize: '12px',
            color: 'var(--text-muted, #6b7280)',
            marginBottom: '28px',
            width: '100%',
            boxSizing: 'border-box',
            display: 'flex',
            alignItems: 'center',
            gap: '8px',
            justifyContent: 'center'
          }}
        >
          <span className="material-symbols-outlined" style={{ fontSize: '16px' }}>
            info
          </span>
          This popup will remain open until you tap &quot;Scanned&quot;.
        </div>

        {/* Action Button */}
        <button
          onClick={onClose}
          style={{
            width: '100%',
            padding: '14px 24px',
            borderRadius: '12px',
            border: 'none',
            background: 'var(--accent, #007aff)',
            color: '#ffffff',
            fontSize: '16px',
            fontWeight: 600,
            cursor: 'pointer',
            boxShadow: '0 4px 14px rgba(0, 122, 255, 0.4)',
            transition: 'all 0.2s ease',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            gap: '8px'
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.transform = 'translateY(-1px)';
            e.currentTarget.style.boxShadow = '0 6px 20px rgba(0, 122, 255, 0.5)';
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.transform = 'translateY(0)';
            e.currentTarget.style.boxShadow = '0 4px 14px rgba(0, 122, 255, 0.4)';
          }}
        >
          <span className="material-symbols-outlined" style={{ fontSize: '20px' }}>
            check_circle
          </span>
          Scanned
        </button>
      </div>
    </div>
  );

  return createPortal(modal, document.body);
};

export default CheckoutQrModal;
